#include<iostream>
#include<cstdio>
#include<cstring>
#include<algorithm>
#include<cmath>
using namespace std;

/////////////////////////////////////////////////

const int N=256;
int n,p,nom[8],dp[N][N],f[N][N],k,ans;
struct node 
{
    int s,num; 
	bool friend operator<(node o,node q) 
	{
	    return o.num<q.num;
	}
}a[505];

/////////////////////////////////////////////////

void F(int b) 
{
    int res=b; 
	for(int i=0;i<=7;++i)
	{
	    if (!(res%nom[i])) 
		a[b].s|=1<<i; 
		while(!(res%nom[i])) 
		{
			res=res/nom[i];
		} 
		a[b].num=res;
	}
}

/////////////////////////////////////////////////

int prime(int l)
{
	if(l<2)return 0;
	if(l==2)return 1;
	for(int i=2;i<=sqrt(l);++i)
	{
		if(l%i==0)
		{
			return 0;
		}
	}
	return 1;
}

/////////////////////////////////////////////////

void F1(int i)
{
	for(int j=N-1;j>=0;--j)
	{
		for(int k=N-1;k>=0;--k)
		{
			if (!(k&a[i].s))
			{
			    f[j|a[i].s][k]=(f[j|a[i].s][k]+f[j][k])%p;
			}
		}
	}
	return;
}

/////////////////////////////////////////////////

void F2(int i)
{
	if(a[i].num!=a[i+1].num||a[i].num==1)
	{
		for(int j=0;j<N;++j)
	    {
		    for(int k=0;k<N;++k)
		    {
			    dp[j][k]=((f[j][k]+f[k][j])%p-dp[j][k])%p;
		    }
	    }
	}
	return;
}

/////////////////////////////////////////////////
int main() 
{
	for(int i=2;i<=20;++i)
	{
		if(prime(i))
		{
			nom[k++]=i;
		}
	}
    cin>>n>>p;int res;
    if(n==2&&p==1)
	{
		cout<<"0";
		return 0;
	}
	
    
	for(int i=2;i<=n;++i)F(i);
	dp[0][0]=1;
	sort(a+2,a+n+1);
	for(int i=2;i<=n;++i)
	{
		if (a[i].num!=a[i-1].num||a[i].num==1) 
		{
			for(int j=0;j<N;++j)
		    {
		    	for(int k=0;k<N;++k)
				{
					f[j][k]=dp[j][k];
				}
		    } 
		}
		F1(i);F2(i);
	} 
	for(int i=0;i<N;++i)
	{
		for(int j=0;j<N;++j)
		{
			ans=(ans+dp[i][j])%p;
		}
	}
	cout<<(ans+p)%p;
	return 0;
}
